const input = $input.first().json;
const body = input.body || input;

// Lexware sends: { resourceId, eventType, organizationId, ... }
// eventType can be "voucher.changed", "payment.changed", "invoice.changed"
// OR separate: resourceType + eventType
const resourceId = body.resourceId || null;

// Handle both formats
let resourceType = (body.resourceType || '').toLowerCase();
let eventAction = '';
const rawEventType = (body.eventType || '').toLowerCase();

if (!resourceType && rawEventType.includes('.')) {
  var parts = rawEventType.split('.');
  resourceType = parts[0];
  eventAction = parts[1];
} else {
  eventAction = rawEventType;
}

// Map to BG event types
const typeMap = {
  'payment': 'LEXWARE_PAYMENT_CHANGED',
  'invoice': 'LEXWARE_INVOICE_CHANGED',
  'voucher': 'LEXWARE_VOUCHER_CHANGED'
};

const bgEventType = typeMap[resourceType] || ('LEXWARE_' + resourceType.toUpperCase() + '_' + eventAction.toUpperCase());

return {
  json: {
    resource_id: resourceId,
    resource_type: resourceType,
    event_type: eventAction,
    bg_event_type: bgEventType,
    is_known_type: !!typeMap[resourceType],
    raw_payload: body
  }
};

